# config/styles.py

LOGO_URI = "data:image/jpeg;base64,"

STYLES = """
<style>

/* ══════════════════════════════════════════
   GLOBAL — white background everywhere
══════════════════════════════════════════ */
html, body { background: #ffffff !important; }

[data-testid="stAppViewContainer"] {
  background: #ffffff !important;
}

/* Main content area — white with logo watermark */
[data-testid="stMain"] {
  background: #ffffff !important;
  position: relative;
}

/* Logo watermark — large, centered, clearly visible */
[data-testid="stMain"]::before {
  content: "";
  position: fixed;
  top: 50%;
  left: 50%;
  transform: translate(-20%, -50%);
  width: 380px;
  height: 380px;
  background-image: url("data:image/jpeg;base64,");
  background-repeat: no-repeat;
  background-position: center center;
  background-size: contain;
  opacity: 0.08;
  pointer-events: none;
  z-index: 0;
}

[data-testid="stVerticalBlock"] {
  position: relative;
  z-index: 1;
}

/* Header toolbar */
[data-testid="stHeader"] {
  background: #ffffff !important;
  border-bottom: 1px solid #EAEBF5;
}

/* ══════════════════════════════════════════
   SIDEBAR — dark
══════════════════════════════════════════ */
[data-testid="stSidebar"] {
  background: #0D0C1A !important;
  border-right: 1px solid #1a1929;
}
[data-testid="stSidebar"] * { color: #9090B0 !important; }
[data-testid="stSidebar"] .stButton > button {
  border-radius: 10px !important;
  font-size: 0.85rem !important;
  transition: all 0.15s !important;
}
[data-testid="stSidebar"] input {
  background: #1a1929 !important;
  color: #fff !important;
  border: 1px solid #2a2940 !important;
  border-radius: 8px !important;
  font-size: 0.82rem !important;
}

/* ══════════════════════════════════════════
   SIDEBAR MODULE BUTTONS
══════════════════════════════════════════ */
.mod-btn-active > button {
  background: linear-gradient(135deg, #6C63FF, #4A42CC) !important;
  color: #fff !important;
  font-weight: 600 !important;
  border: none !important;
  box-shadow: 0 2px 8px rgba(108,99,255,0.35) !important;
}
.mod-btn-inactive > button {
  background: transparent !important;
  color: #555 !important;
  border: none !important;
}
.mod-btn-inactive > button:hover {
  background: #1a1929 !important;
  color: #aaa !important;
}
.mod-btn-locked > button {
  background: transparent !important;
  color: #2a2940 !important;
  border: none !important;
  cursor: not-allowed !important;
}

/* ══════════════════════════════════════════
   MAIN CONTENT LAYOUT
══════════════════════════════════════════ */
.block-container {
  padding: 2rem 3rem !important;
  max-width: 840px !important;
  margin: 0 auto;
  background: transparent !important;
}

/* ══════════════════════════════════════════
   STEP HEADER
══════════════════════════════════════════ */
.step-hdr { margin-bottom: 1.8rem; }
.step-hdr h1 {
  font-size: 1.55rem;
  font-weight: 700;
  color: #1a1a2e;
  margin: 0 0 0.2rem;
  letter-spacing: -0.01em;
}
.step-hdr p { color: #999; font-size: 0.87rem; margin: 0; }

/* ══════════════════════════════════════════
   CHAT BUBBLES
══════════════════════════════════════════ */
.chat-wrap {
  display: flex;
  flex-direction: column;
  gap: 0.65rem;
  margin-bottom: 1.5rem;
}
.bubble-ai {
  background: #ffffff;
  border: 1px solid #E8E9F5;
  border-radius: 0 14px 14px 14px;
  padding: 0.8rem 1.1rem;
  max-width: 80%;
  font-size: 0.9rem;
  color: #1a1a2e;
  box-shadow: 0 2px 8px rgba(0,0,0,0.05);
  line-height: 1.55;
}
.bubble-user {
  background: linear-gradient(135deg, #6C63FF, #4A42CC);
  border-radius: 14px 14px 0 14px;
  padding: 0.8rem 1.1rem;
  max-width: 80%;
  margin-left: auto;
  font-size: 0.9rem;
  color: #fff;
  line-height: 1.55;
  box-shadow: 0 2px 8px rgba(108,99,255,0.25);
}
.bubble-label {
  font-size: 0.62rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  margin-bottom: 4px;
  color: #bbb;
}
.bubble-label.user {
  color: rgba(255,255,255,0.55);
  text-align: right;
}

/* ══════════════════════════════════════════
   SUMMARY TABLE
══════════════════════════════════════════ */
.sum-wrap {
  background: #ffffff;
  border: 1px solid #E8E9F5;
  border-radius: 14px;
  overflow: hidden;
  margin: 1.5rem 0;
  box-shadow: 0 2px 16px rgba(108,99,255,0.07);
}
.sum-row { display: flex; border-bottom: 1px solid #F2F2FA; }
.sum-row:last-child { border-bottom: none; }
.sum-key {
  width: 38%;
  padding: 0.75rem 1.1rem;
  font-size: 0.72rem;
  font-weight: 700;
  color: #6C63FF;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  background: #FAFAFF;
  border-right: 1px solid #F2F2FA;
}
.sum-val {
  flex: 1;
  padding: 0.75rem 1.1rem;
  font-size: 0.88rem;
  color: #1a1a2e;
  line-height: 1.5;
}

/* ══════════════════════════════════════════
   REFERENCE ID BOX
══════════════════════════════════════════ */
.ref-wrap {
  background: #0D0C1A;
  border: 1px solid #6C63FF;
  border-radius: 12px;
  padding: 1rem 1.4rem;
  margin: 1.2rem 0;
  display: flex;
  justify-content: space-between;
  align-items: center;
  box-shadow: 0 4px 16px rgba(108,99,255,0.15);
}
.ref-id {
  font-family: monospace;
  font-size: 1.05rem;
  font-weight: 700;
  color: #a89fff;
  letter-spacing: 0.04em;
}
.ref-meta {
  font-size: 0.7rem;
  color: #555;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  margin-bottom: 3px;
}

/* ══════════════════════════════════════════
   STATUS BADGES
══════════════════════════════════════════ */
.badge {
  display: inline-block;
  padding: 3px 11px;
  border-radius: 20px;
  font-size: 0.73rem;
  font-weight: 700;
}
.b-submitted { background: #EDE9FF; color: #4A42CC; }
.b-review    { background: #FFF3CD; color: #856404; }
.b-approved  { background: #D1F5EA; color: #0f6e56; }
.b-rejected  { background: #FDE8E8; color: #c0392b; }
.b-deferred  { background: #F0F0F0; color: #555; }

/* ══════════════════════════════════════════
   COMING SOON
══════════════════════════════════════════ */
.coming-wrap {
  text-align: center;
  padding: 5rem 2rem;
  color: #ccc;
}
.coming-wrap h2 { font-size: 1.2rem; color: #ccc; margin: 0.5rem 0; }

/* ══════════════════════════════════════════
   M2 SCORE BARS
══════════════════════════════════════════ */
.score-row { margin-bottom: 1rem; }
.score-row .s-label {
  display: flex;
  justify-content: space-between;
  font-size: 0.82rem;
  color: #444;
  margin-bottom: 4px;
}
.score-bar-bg   { background: #F0F0F8; border-radius: 6px; height: 8px; }
.score-bar-fill { height: 8px; border-radius: 6px; transition: width 0.4s; }

/* ══════════════════════════════════════════
   STREAMLIT NATIVE ELEMENTS — white theme
══════════════════════════════════════════ */
div[data-testid="stChatInput"] textarea {
  background: #ffffff !important;
  border-radius: 12px !important;
  border: 1px solid #E8E9F5 !important;
}
.stTextInput input, .stSelectbox select {
  background: #ffffff !important;
  border: 1px solid #E8E9F5 !important;
  border-radius: 8px !important;
}
div[data-testid="stExpander"] {
  background: #ffffff !important;
  border: 1px solid #E8E9F5 !important;
  border-radius: 12px !important;
}

</style>
"""
